+      project: 'text-blue-400',
+      files: 'text-green-400',
+      git: 'text-orange-400',
+      development: 'text-purple-400',
+      ai: 'text-cyan-400',
+      system: 'text-gray-400',
+    };
+    return colors[category as keyof typeof colors] || 'text-gray-400';
+  }
